import { agentConfig } from '@mastra/core/agent'

export default agentConfig({
  model: 'anthropic/claude-sonnet-4-6',
})

import { Memory } from '@mastra/memory'

export default new Memory({
  options: {
    lastMessages: 10,
  },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'

export default createTool({
  id: 'parse_github_url',
  description:
    'Parses a GitHub pull request URL and extracts the owner, repository name, and PR number.',
  inputSchema: z.object({
    url: z.string().url().describe('GitHub pull request URL'),
  }),
  outputSchema: z.object({
    owner: z.string(),
    repo: z.string(),
    prNumber: z.number(),
  }),
  execute: async (inputData) => {
    const { url } = inputData
    const match = url.match(/^https?:\/\/github\.com\/([^/]+)\/([^/]+)\/pull\/(\d+)/)
    if (!match) {
      throw new Error(`Invalid GitHub PR URL: ${url}`)
    }
    return {
      owner: match[1],
      repo: match[2],
      prNumber: parseInt(match[3], 10),
    }
  },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'

const GITHUB_API = 'https://api.github.com'

const headers = () => ({
  Accept: 'application/vnd.github+json',
  Authorization: `Bearer ${process.env.GITHUB_TOKEN ?? ''}`,
  'X-GitHub-Api-Version': '2022-11-28',
})

export default createTool({
  id: 'get_pr_files',
  description: 'Gets the list of files changed in a GitHub pull request.',
  inputSchema: z.object({
    owner: z.string().describe('Repository owner (user or organization)'),
    repo: z.string().describe('Repository name'),
    prNumber: z.number().describe('Pull request number'),
  }),
  outputSchema: z.object({
    files: z.array(
      z.object({
        filename: z.string(),
        status: z.string(),
        additions: z.number(),
        deletions: z.number(),
      }),
    ),
  }),
  execute: async (inputData) => {
    const { owner, repo, prNumber } = inputData
    const url = `${GITHUB_API}/repos/${owner}/${repo}/pulls/${prNumber}/files?per_page=100`
    const data = await fetch(url, { headers: headers() }).then((r) => r.json())
    return {
      files: (data as any[]).map((f) => ({
        filename: f.filename as string,
        status: f.status as string,
        additions: f.additions as number,
        deletions: f.deletions as number,
      })),
    }
  },
})

import { createTool } from '@mastra/core/tools'
import { z } from 'zod'

const GITHUB_API = 'https://api.github.com'

const headers = () => ({
  Accept: 'application/vnd.github+json',
  Authorization: `Bearer ${process.env.GITHUB_TOKEN ?? ''}`,
  'X-GitHub-Api-Version': '2022-11-28',
})

export default createTool({
  id: 'get_file_content',
  description:
    'Gets the raw content of a specific file from a GitHub repository.',
  inputSchema: z.object({
    owner: z.string().describe('Repository owner (user or organization)'),
    repo: z.string().describe('Repository name'),
    filePath: z.string().describe('Path to the file in the repository'),
    ref: z
      .string()
      .optional()
      .describe('Branch, tag, or commit SHA (defaults to the default branch)'),
  }),
  outputSchema: z.object({
    content: z.string(),
    encoding: z.string(),
  }),
  execute: async (inputData) => {
    const { owner, repo, filePath, ref } = inputData
    const url = new URL(
      `${GITHUB_API}/repos/${owner}/${repo}/contents/${filePath}`,
    )
    if (ref) url.searchParams.set('ref', ref)
    const data = await fetch(url.toString(), { headers: headers() }).then(
      (r) => r.json(),
    )
    if (data.encoding === 'base64') {
      return {
        content: Buffer.from(data.content as string, 'base64').toString('utf-8'),
        encoding: 'utf-8',
      }
    }
    return {
      content: (data.content as string) ?? '',
      encoding: (data.encoding as string) ?? 'none',
    }
  },
})
